                            Web.SetUserAgent(true);
                        #elif UNITY_IOS
                            // On iOS, change the User-Agent to desktop:
                            Web.SetUserAgent(false);
                        #elif UNITY_ANDROID
                            // On Android, change the User-Agent to "random":
                            Web.SetUserAgent("random");
                        #endif
